Here's an example implementation using **Express** and **Node.js** to extract images from a given URL. Note that web scraping should comply with the website's `robots.txt` and terms of service.

```javascript
const express = require('express');
const axios = require('axios');
const fs = require('fs');
const path = require('path');
const cheerio = require('cheerio');

const app = express();
const PORT = 3000;

app.get('/scrape', async (req, res) => {
  const { tag } = req.query;
  if (!tag) {
    return res.status(400).json({ error: 'Please provide a "tag" parameter' });
  }

  const url = `https://www.pornpics.com/tags/${tag}`;
  let images = [];

  try {
    // Download the page HTML
    const response = await axios.get(url, {
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/58.0.3029.110 Safari/537.3'
      }
    });

    const html = response.data;
    const $ = cheerio.load(html);

    // Extract <img> src attributes (add more selectors if needed)
    $('img').each((i, element) => {
      const src = $(element).attr('src');
      if (src && src.startsWith('http')) {
        images.push(src);
      }
    });

    if (images.length === 0) {
      return res.status(404).json({ message: 'No images found' });
    }

    // Save images to disk (client-side only)
    const savedImages = await Promise.all(
      images.map(async (imgUrl) => {
        try {
          const imgResponse = await axios.get(imgUrl, {
            responseType: 'arraybuffer',
            headers: { 'User-Agent': 'same-browser-agent' }
          });

          const ext = imgUrl.split('.').pop();
          const uniqueName = `${Date.now()}-${Math.random()}.${ext}`;
          const outputPath = path.join(__dirname, 'downloads', uniqueName);

          // Create directory if it doesn't exist
          if (!fs.existsSync(path.dirname(outputPath))) {
            fs.mkdirSync(path.dirname(outputPath), { recursive: true });
          }

          fs.writeFileSync(outputPath, imgResponse.data);
          return { url: `http://localhost:${PORT}/images/${uniqueName}`, originalUrl: imgUrl };
        } catch (err) {
          console.error(`Failed to download image: ${imgUrl}`, err);
          return { originalUrl: imgUrl, error: 'Download failed' };
        }
      })
    );

    res.json({
      totalImages: images.length,
      successfulDownloads: savedImages.filter(img => !img.error).length,
      images: savedImages
    });

  } catch (error) {
    console.error('Scraping error:', error.message);
    res.status(500).json({ error: 'Failed to fetch the webpage' });
  }
});

// Serve downloaded images
app.use('/images', express.static(path.join(__dirname, 'downloads')));

app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
});
```

**Prerequisites:**
1. Install required packages:
   ```bash
   npm install express axios cheerio
   ```
2. Create a `downloads` directory in your project root

**Important Considerations:**
1. **Legal/Ethical:**
   - Check `https://www.pornpics.com/robots.txt` before scraping
   - Verify site's terms of service
   - Consider using official APIs if available

2. **Limitations:**
   - Basic image extraction - adds CSS/JS for better extraction in production
   - Images get downloaded to server's disk
   - Requires proper error handling and rate limiting

3. **To Convert to Pure Extraction (No File Saving):**
   Modify the route handler to simply return image URLs instead of saving files:
   ```javascript
